		resp.State.Run.Jobs = nil
		for i, j := range mockJobs {
			id := runID*1000 + int64(i)
			resp.State.Run.Jobs = append(resp.State.Run.Jobs, &actions.ViewJob{
				ID:       id,
				Link:     jobLink(id),
				JobID:    j.jobID,
				Name:     j.name,
				Status:   j.status.String(),
