		//   prepare           (regular, top-level)
		//   local_caller      (caller, same-repo, expanded)
		//     ├ lib_step      (regular)
		//     └ inner_caller  (caller, same-repo nested, expanded)
		//       └ deep_job    (regular)
		//   cross_caller      (caller, cross-repo, expanded)
		//     └ external_job  (regular)
